<section class="v4-page-shell"><div class="v4-page-head"><h1>Revision Restore Center</h1><p>Draft restore آمن أو Live restore مع backup snapshot.</p></div>
<?php if (!empty($flash)): ?><div class="v4-flash v4-flash-<?= e($flash['type'] ?? 'info') ?>"><?= e($flash['message'] ?? '') ?></div><?php endif; ?>
<form class="v4-search-form" method="get" action="<?= e(godyar_v4_base_url('/v4/admin/revisions')) ?>"><input type="number" name="news_id" min="1" placeholder="رقم الخبر" value="<?= (int)($newsId ?? 0) ?: '' ?>"><button type="submit">عرض السجل</button></form>
<?php if (!empty($items)): ?><div class="v4-table-wrap"><table class="v4-table"><thead><tr><th>ID</th><th>المحرر</th><th>التاريخ</th><th>ملاحظة</th><th>Draft</th><th>Live</th></tr></thead><tbody><?php foreach ($items as $item): ?><tr><td><code><?= e($item['id'] ?? '') ?></code></td><td><?= e($item['editor_name'] ?? '') ?></td><td><?= e($item['created_at'] ?? '') ?></td><td><?= e($item['note'] ?? '') ?></td><td><form method="post" action="<?= e(godyar_v4_base_url('/v4/admin/revisions/restore')) ?>"><?= godyar_v4_csrf_field() ?><input type="hidden" name="news_id" value="<?= (int)($newsId ?? 0) ?>"><input type="hidden" name="revision_id" value="<?= e($item['id'] ?? '') ?>"><button type="submit" class="v4-btn-ghost">Draft</button></form></td><td><form method="post" action="<?= e(godyar_v4_base_url('/v4/admin/revisions/live-restore')) ?>" onsubmit="return confirm('سيتم إنشاء backup ثم محاولة الكتابة على المحتوى الحي.');"><?= godyar_v4_csrf_field() ?><input type="hidden" name="news_id" value="<?= (int)($newsId ?? 0) ?>"><input type="hidden" name="revision_id" value="<?= e($item['id'] ?? '') ?>"><button type="submit" class="v4-btn-danger">Live</button></form></td></tr><?php endforeach; ?></tbody></table></div><?php else: ?><div class="v4-empty-state"><p>أدخل رقم خبر يملك snapshots داخل <code>storage/revisions</code>.</p></div><?php endif; ?></section>
